def binary_search(arr, target):
    """
    在有序数组 arr 中查找目标值 target。
    返回目标值的索引，若不存在则返回 -1。
    """
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

